# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import os
import json
import threading
from datetime import datetime
from collections import Counter, defaultdict
from flask import Flask, request, jsonify
import numpy as np
from PIL import Image
import io

app = Flask(__name__)

# In-memory storage for labels and images
labels_storage = defaultdict(list)  # image_id -> list of (annotator_id, label, timestamp)
images_storage = {}  # image_id -> image_data
aggregated_labels = {}  # image_id -> aggregated_label
training_data = []  # list of (image_id, label) tuples
model_weights = None
lock = threading.Lock()


@app.route('/api/upload_image', methods=['POST'])
def upload_image():
    """Upload an image for labeling"""
    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided'}), 400
    
    image_file = request.files['image']
    image_id = request.form.get('image_id')
    
    if not image_id:
        image_id = f"img_{datetime.now().strftime('%Y%m%d%H%M%S%f')}"
    
    try:
        image_data = image_file.read()
        with lock:
            images_storage[image_id] = image_data
        
        return jsonify({
            'status': 'success',
            'image_id': image_id,
            'message': 'Image uploaded successfully'
        }), 201
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/submit_label', methods=['POST'])
def submit_label():
    """Submit a label for an image"""
    data = request.json
    
    if not data or 'image_id' not in data or 'label' not in data or 'annotator_id' not in data:
        return jsonify({'error': 'Missing required fields: image_id, label, annotator_id'}), 400
    
    image_id = data['image_id']
    label = data['label']
    annotator_id = data['annotator_id']
    
    with lock:
        if image_id not in images_storage:
            return jsonify({'error': 'Image not found'}), 404
        
        timestamp = datetime.now().isoformat()
        labels_storage[image_id].append({
            'annotator_id': annotator_id,
            'label': label,
            'timestamp': timestamp
        })
    
    return jsonify({
        'status': 'success',
        'message': 'Label submitted successfully',
        'image_id': image_id,
        'label': label
    }), 201


@app.route('/api/submit_labels_batch', methods=['POST'])
def submit_labels_batch():
    """Submit multiple labels at once"""
    data = request.json
    
    if not data or 'labels' not in data:
        return jsonify({'error': 'Missing labels array'}), 400
    
    labels_list = data['labels']
    results = []
    
    with lock:
        for label_entry in labels_list:
            if 'image_id' not in label_entry or 'label' not in label_entry or 'annotator_id' not in label_entry:
                results.append({'error': 'Missing required fields', 'entry': label_entry})
                continue
            
            image_id = label_entry['image_id']
            label = label_entry['label']
            annotator_id = label_entry['annotator_id']
            
            if image_id not in images_storage:
                results.append({'error': 'Image not found', 'image_id': image_id})
                continue
            
            timestamp = datetime.now().isoformat()
            labels_storage[image_id].append({
                'annotator_id': annotator_id,
                'label': label,
                'timestamp': timestamp
            })
            results.append({'status': 'success', 'image_id': image_id})
    
    return jsonify({'results': results}), 200


@app.route('/api/get_labels/<image_id>', methods=['GET'])
def get_labels(image_id):
    """Get all labels for an image"""
    with lock:
        if image_id not in labels_storage:
            return jsonify({'error': 'No labels found for this image'}), 404
        
        labels = labels_storage[image_id]
    
    return jsonify({
        'image_id': image_id,
        'labels': labels,
        'count': len(labels)
    }), 200


@app.route('/api/aggregate_labels', methods=['POST'])
def aggregate_labels():
    """Aggregate labels using majority voting"""
    data = request.json
    min_annotations = data.get('min_annotations', 3) if data else 3
    
    aggregated = {}
    
    with lock:
        for image_id, labels_list in labels_storage.items():
            if len(labels_list) >= min_annotations:
                label_counts = Counter([entry['label'] for entry in labels_list])
                most_common_label, count = label_counts.most_common(1)[0]
                
                aggregated[image_id] = {
                    'label': most_common_label,
                    'votes': count,
                    'total_annotations': len(labels_list),
                    'confidence': count / len(labels_list),
                    'label_distribution': dict(label_counts)
                }
        
        aggregated_labels.update(aggregated)
    
    return jsonify({
        'status': 'success',
        'aggregated_count': len(aggregated),
        'aggregated_labels': aggregated
    }), 200


@app.route('/api/get_aggregated_label/<image_id>', methods=['GET'])
def get_aggregated_label(image_id):
    """Get aggregated label for a specific image"""
    with lock:
        if image_id not in aggregated_labels:
            return jsonify({'error': 'No aggregated label found for this image'}), 404
        
        result = aggregated_labels[image_id]
    
    return jsonify({
        'image_id': image_id,
        'aggregated_label': result
    }), 200


@app.route('/api/prepare_training_data', methods=['POST'])
def prepare_training_data():
    """Prepare training data from aggregated labels"""
    global training_data
    
    with lock:
        training_data = [(image_id, agg['label']) for image_id, agg in aggregated_labels.items()]
    
    return jsonify({
        'status': 'success',
        'training_samples': len(training_data),
        'message': f'Prepared {len(training_data)} training samples'
    }), 200


@app.route('/api/train_model', methods=['POST'])
def train_model():
    """Train a simple model on labeled data without validation"""
    global model_weights
    
    if not training_data:
        return jsonify({'error': 'No training data available. Run prepare_training_data first.'}), 400
    
    data = request.json
    num_classes = data.get('num_classes', 10) if data else 10
    epochs = data.get('epochs', 5) if data else 5
    learning_rate = data.get('learning_rate', 0.01) if data else 0.01
    
    with lock:
        label_to_idx = {}
        current_idx = 0
        
        X_train = []
        y_train = []
        
        for image_id, label in training_data:
            if image_id not in images_storage:
                continue
            
            if label not in label_to_idx:
                label_to_idx[label] = current_idx
                current_idx += 1
            
            try:
                image_bytes = images_storage[image_id]
                img = Image.open(io.BytesIO(image_bytes))
                img = img.convert('RGB')
                img = img.resize((32, 32))
                img_array = np.array(img).flatten() / 255.0
                
                X_train.append(img_array)
                y_train.append(label_to_idx[label])
            except Exception as e:
                continue
        
        if not X_train:
            return jsonify({'error': 'No valid training images found'}), 400
        
        X_train = np.array(X_train)
        y_train = np.array(y_train)
        
        num_features = X_train.shape[1]
        num_classes = len(label_to_idx)
        
        weights = np.random.randn(num_features, num_classes) * 0.01
        bias = np.zeros(num_classes)
        
        for epoch in range(epochs):
            logits = X_train @ weights + bias
            exp_logits = np.exp(logits - np.max(logits, axis=1, keepdims=True))
            probs = exp_logits / np.sum(exp_logits, axis=1, keepdims=True)
            
            targets = np.zeros_like(probs)
            targets[np.arange(len(y_train)), y_train] = 1
            
            grad_logits = probs - targets
            grad_weights = X_train.T @ grad_logits / len(X_train)
            grad_bias = np.mean(grad_logits, axis=0)
            
            weights -= learning_rate * grad_weights
            bias -= learning_rate * grad_bias
            
            loss = -np.mean(np.log(probs[np.arange(len(y_train)), y_train] + 1e-10))
        
        model_weights = {
            'weights': weights.tolist(),
            'bias': bias.tolist(),
            'label_to_idx': label_to_idx,
            'idx_to_label': {v: k for k, v in label_to_idx.items()},
            'num_features': num_features,
            'num_classes': num_classes
        }
    
    return jsonify({
        'status': 'success',
        'message': 'Model trained successfully',
        'training_samples': len(X_train),
        'num_classes': num_classes,
        'epochs': epochs,
        'final_loss': float(loss)
    }), 200


@app.route('/api/predict', methods=['POST'])
def predict():
    """Predict label for an image"""
    if model_weights is None:
        return jsonify({'error': 'Model not trained yet'}), 400
    
    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided'}), 400
    
    image_file = request.files['image']
    
    try:
        image_data = image_file.read()
        img = Image.open(io.BytesIO(image_data))
        img = img.convert('RGB')
        img = img.resize((32, 32))
        img_array = np.array(img).flatten() / 255.0
        
        weights = np.array(model_weights['weights'])
        bias = np.array(model_weights['bias'])
        idx_to_label = model_weights['idx_to_label']
        
        logits = img_array @ weights + bias
        exp_logits = np.exp(logits - np.max(logits))
        probs = exp_logits / np.sum(exp_logits)
        
        predicted_idx = int(np.argmax(probs))
        predicted_label = idx_to_label[str(predicted_idx)]
        confidence = float(probs[predicted_idx])
        
        return jsonify({
            'predicted_label': predicted_label,
            'confidence': confidence,
            'probabilities': {idx_to_label[str(i)]: float(probs[i]) for i in range(len(probs))}
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/get_stats', methods=['GET'])
def get_stats():
    """Get system statistics"""
    with lock:
        total_images = len(images_storage)
        total_labels = sum(len(labels) for labels in labels_storage.values())
        images_with_labels = len(labels_storage)
        aggregated_count = len(aggregated_labels)
        training_samples_count = len(training_data)
        
        annotator_counts = defaultdict(int)
        for labels_list in labels_storage.values():
            for entry in labels_list:
                annotator_counts[entry['annotator_id']] += 1
    
    return jsonify({
        'total_images': total_images,
        'total_labels': total_labels,
        'images_with_labels': images_with_labels,
        'aggregated_labels': aggregated_count,
        'training_samples': training_samples_count,
        'model_trained': model_weights is not None,
        'annotator_counts': dict(annotator_counts),
        'unique_annotators': len(annotator_counts)
    }), 200


@app.route('/api/reset', methods=['POST'])
def reset():
    """Reset all data"""
    global labels_storage, images_storage, aggregated_labels, training_data, model_weights
    
    with lock:
        labels_storage = defaultdict(list)
        images_storage = {}
        aggregated_labels = {}
        training_data = []
        model_weights = None
    
    return jsonify({'status': 'success', 'message': 'All data reset'}), 200


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)